import booksData from "../data/booksData";
import { useNavigate } from "react-router-dom";
import "./styles/LibrarianBooks.css";

function LibrarianGenreSummary() {
  const navigate = useNavigate();
  const genre = localStorage.getItem("genre");

  if (!genre || !booksData[genre]) {
    return (
      <div style={{ padding: "40px" }}>
        <h2>Genre not found</h2>
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    );
  }

  const books = booksData[genre];
  const statusKey = `status_${genre}`;
  const statusMap =
    JSON.parse(localStorage.getItem(statusKey)) || {};

  const totalBooks = books.length;

  const borrowedBooks = books.filter(
    (book) => statusMap[book.title] === "Not Available"
  ).length;

  const availableBooks = totalBooks - borrowedBooks;

  return (
    <div className="books-page">
      <h1 className="books-title">{genre} Books Summary</h1>

      <div
        style={{
          maxWidth: "420px",
          margin: "auto",
          background: "linear-gradient(135deg,#3b2416,#6b3f25)",
          padding: "30px",
          borderRadius: "18px",
          color: "#f5e6cf",
          textAlign: "center",
          boxShadow: "0 20px 40px rgba(0,0,0,0.35)",
        }}
      >
        <h2 style={{ marginBottom: "20px" }}>{genre}</h2>

        <p><strong>Total Books:</strong> {totalBooks}</p>
        <p><strong>Available Books:</strong> {availableBooks}</p>
        <p><strong>Borrowed Books:</strong> {borrowedBooks}</p>
      </div>

      <div className="action-buttons">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    </div>
  );
}

export default LibrarianGenreSummary;
